#include<bits/stdc++.h>
#define p(x,y) (((x)-1)*n+(y))
using namespace std;
struct edge
{
    long long to,val,nxt,cost;
}e[2000010];
long long head[2000010],tot=1,res;
long long n,m,s,t,d[2000010],now[2000010];
bool vis[2000010];
void add1(long long u,long long v,long long w,long long c)
{
    e[++tot]=(edge){v,w,head[u],c};
    head[u]=tot;
}
void add(long long u,long long v,long long w,long long c)
{
    add1(u,v,w,c);
    add1(v,u,0,-c);
}
bool spfa()
{
    memset(d,0x3f,sizeof(d));
    long long tmp=d[0];
    queue<long long> q;
    q.push(s);
    d[s]=0;
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        vis[t]=false;
        for(int i=head[t];i;i=e[i].nxt)
        {
            int v=e[i].to,cost=e[i].cost;
            if(e[i].val&&d[v]>d[t]+cost)
            {
                d[v]=d[t]+cost;
                if(!vis[v])
                {
                    vis[v]=true;
                    q.push(v);
                }
            }
        }
    }
    return d[t]<tmp;
}
long long dfs(long long x,long long flow)
{
    if(x==t)
    {
        return flow;
    }
    vis[x]=true;
    long long sum=0;
    for(long long i=now[x];i;i=e[i].nxt)
    {
        now[x]=i;
        long long v=e[i].to,val=e[i].val,cost=e[i].cost;
        if(!vis[v]&&d[v]==d[x]+cost&&val)
        {
            long long tmp=dfs(v,min(flow,val));
            e[i].val-=tmp;
            e[i^1].val+=tmp;
            sum+=tmp;
            res+=tmp*cost;
            flow-=tmp;
        }
    }
    vis[x]=false;
    return sum;
}
long long dinic()
{
    long long ans=0;
    while(spfa())
    {
        memcpy(now,head,sizeof(head));
        ans+=dfs(s,INT_MAX);
    }
    return ans;
}
int main()
{
    long long k,a,b,c;
    scanf("%lld%lld%lld%lld%lld",&n,&k,&a,&b,&c);
    s=0;
    t=1000999;
    add(s,p(1,1),1,0);
    for(int i=0;i<=k;i++)
    {
        add(p(n,n)+10001*i,t,1,0);
    }
    int K=k;
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=n;j++)
        {
            int x;
            scanf("%d",&x);
            if(x)
            {
                for(int k=1;k<=K;k++)
                {
                    add(p(i,j)+k*10001,p(i,j),1,a);
                }
            }
            for(int k=0;k<K;k++)
            {
                if(x&&k)
                {
                    break;
                }
                if(i+1<=n)
                {
                    add(p(i,j)+k*10001,p(i+1,j)+(k+1)*10001,2e9,0);
                }
                if(j+1<=n)
                {
                    add(p(i,j)+k*10001,p(i,j+1)+(k+1)*10001,2e9,0);
                }
                if(i-1>=1)
                {
                    add(p(i,j)+k*10001,p(i-1,j)+(k+1)*10001,2e9,b);
                }
                if(j-1>=1)
                {
                    add(p(i,j)+k*10001,p(i,j-1)+(k+1)*10001,2e9,b);
                }
            }
            add(p(i,j)+k*10001,p(i,j),1,a+c);
        }
    }
    dinic();
    printf("%lld",res);
    return 0;
}
